#include <stdio.h>
int main() {
    int N, Q;
    scanf("%d %d", &N, &Q);
    int A[N];
    for (int i = 0; i < N; i++) {
        scanf("%d", &A[i]);
    }
    for (int i = 0; i < Q; i++) {
        int type, L, R, K;
        scanf("%d %d %d", &type, &L, &R);
        L--;
        R--;
        if (type == 1) {
            int min = A[L];
            int count = 0;
            for (int j = L; j <= R; j++) {
                if (A[j] < min) {
                    min = A[j];
                    count = 1;
                } else if (A[j] == min) {
                    count++;
                }
            }
            printf("%d %d\n", min, count);
        } else {
            scanf("%d", &K);
            for (int j = L; j <= R; j++) {
                A[j] ^= K;
            }
        }
    }
    return 0;
}

