import java.util.Scanner;
public class Main {
    public static void main(String[] args) {
        Scanner sc = new Scanner(System.in);
        int N = sc.nextInt();
        int Q = sc.nextInt();
        int[] A = new int[N];
        for (int i = 0; i < N; i++) {
            A[i] = sc.nextInt();
        }
        for (int i = 0; i < Q; i++) {
            int type = sc.nextInt();
            int L = sc.nextInt() - 1;
            int R = sc.nextInt() - 1;
            if (type == 1) {
                int min = A[L];
                int count = 0;
                for (int j = L; j <= R; j++) {
                    if (A[j] < min) {
                        min = A[j];
                        count = 1;
                    } else if (A[j] == min) {
                        count++;
                    }
                }
                System.out.println(min + " " + count);
            } else {
                int K = sc.nextInt();
                for (int j = L; j <= R; j++) {
                    A[j] ^= K;
                }
            }
        }
    }
}

